{
  "verses": [
    {
      "n": 10,
      "column": "left",
      "text": "Un kad Jehkabs Raëli / wahjas/ bet Raëlei bija raschene\nfawas Mahtes Brahta Lahbana un skaifts Gihmis.\nMeitu eeraudsija / un fawas\nMahtes Brahta Lahbana Awis/\ntad peegahje tas/ un nowehle to\nAfmini no tahs Akkas Zau-\nruma."
    },
    {
      "n": 11,
      "column": "left",
      "text": "Un dfirdtja fawas Ma-\ntes Brahta Lahbana Awis/ un\nJehkabs skuhpstija Raëli / un pa-\nzehle fawn Balfi/ un raundaja."
    },
    {
      "n": 12,
      "column": "left",
      "text": "Un Jehkabs pafazztja Ra-\nelei/ ka wiꞥſch winnas Tehwa\nBrahlis effus/ un ka wiꞥſch Re-\nbekas Dehls effus / tad tezzeja\nta/ un pafazztija to fawam Teh-\nwam."
    },
    {
      "n": 13,
      "column": "left",
      "text": "Un kad Lahbans tahs\nWehſtis no Jehkaba / fawas\nMahfas Dehla / dsirdeja / tad\ntezczeja tas winnam pretti/ un\napkanpe winnu! / un skuhpstija\nwinnu/ un eetwedde winnu tawā\nNamna. Tad isteize tas Lah-\nbanain wiffas schahs Leetas."
    },
    {
      "n": 14,
      "column": "left",
      "text": "Un Lahbanas fazztja us\nwinnu : Teefcham tu effi no\nmanneem Kanleem/ un no man-\nnas Meeſas/ un wiꞥſch mitte pee\nta zaur angoschtu Mehnefi."
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un Lahbans fazztja us\nJehkabu : Jepſchu tu mans\nBrahlis effi / buhtu tadeht tu\nman weliti kalpojis? fakki man/\nfo praffi tu Algai?"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Un Lahbanam bij diwi\nMeitas/ tahs wezzakas Wahrdē\nbija Lea / un tahs jaunakas\nWahrdē bija Raële."
    },
    {
      "n": 17,
      "column": "left",
      "text": "Bet Leas Azzis bija pa-"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un Jehkabs mihtleja to\nRaëli/ un fazztja : Es gribbu ten-\nseptin Gaddus kalpoht/ par Ra-\neli tawu jaunaku Meitu."
    },
    {
      "n": 19,
      "column": "right",
      "text": "Tad fazztja Lahbans\nLabbaki es tew to dohmu/ ne ka\nes to zittam Wihram dohmu/ pa-\nleez pee mannis."
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un Jehkabs kalpoja pa-\nRaëli septin Gaddus / winſc\nschkitte tohs mag Deenas effo-\nschas/ tik mihti tas to turreja."
    },
    {
      "n": 21,
      "column": "right",
      "text": "Un Jehkabs fazztja u\nLahbann: Dohd man mannis\nSeewu/ jo tahs Deenas irr pee-\npilditas/ ka es pee tahs eemiu."
    },
    {
      "n": 22,
      "column": "right",
      "text": "Tad japulzeja Lahban\nwiffus tahs Weetas Lauds/ un\npadarrija Weefibas."
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un Wakkarā nehme winſc\nfawn Meitu Leū/ un eetwedde ta-\npee winna/ un Jehkabs gahje pe-\ntahs."
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un Lahbans detwe fatw\nKalpoui Silpu Leai/ fawai Mer-\ntai par Kalpont."
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un tas notifke Rihta-\ntad raugi/ ta bija Lea/ tad fa-\nzija wiꞥſch us Lahbann: Kas ta-\nes par Raëli pee tew efmu ka-\npojis/ kam tu maneſi prewihlis"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Tad fazztja Lahbane\nMuhtu Semmē ne mehōsto jan-\nnaku preeſch tahs Pirundsimta-\nisdoht."
    },
    {
      "n": 27,
      "column": "right",
      "text": "Beids ar schahs to Ne-\ndetu/ tad dohſchu es tew win-\narrid"
    }
  ],
  "confidence": "high",
  "notes": ""
}
